{
  "sentences": [
    {
      "text": "今天天氣有點冷，我有點擔心。",
      "pinyin": "Jīntiān tiānqì yǒudiǎn lěng, wǒ yǒudiǎn dānxīn.",
      "pinyin_numeric": "jin1tian1 tian1qi4 you3dian3 leng3, wo3 you3dian3 dan1xin1.",
      "translation_en": "The weather is a bit cold today, and I'm a little worried.",
      "translation_ko": "오늘 날씨가 조금 춥고, 저는 조금 걱정됩니다."
    },
    {
      "text": "颱風要來了，我心情有點緊張。",
      "pinyin": "Táifēng yào lái le, wǒ xīnqíng yǒudiǎn jǐnzhāng.",
      "pinyin_numeric": "tai2feng1 yao4 lai2 le0, wo3 xin1qing2 you3dian3 jin3zhang1.",
      "translation_en": "A typhoon is coming, and I'm feeling a bit nervous.",
      "translation_ko": "태풍이 오려고 해서, 제 기분이 조금 긴장됩니다."
    },
    {
      "text": "今天下午有點悶熱，我有點沒精神。",
      "pinyin": "Jīntiān xiàwǔ yǒudiǎn mēnrè, wǒ yǒudiǎn méi jīngshén.",
      "pinyin_numeric": "jin1tian1 xia4wu3 you3dian3 men1re4, wo3 you3dian3 mei2 jing1shen2.",
      "translation_en": "This afternoon is a bit muggy, and I'm feeling a little lethargic.",
      "translation_ko": "오늘 오후가 조금 후덥지근해서, 저는 조금 기운이 없습니다."
    },
    {
      "text": "昨天是晴天，我心情很開心。",
      "pinyin": "Zuótiān shì qíngtiān, wǒ xīnqíng hěn kāixīn.",
      "pinyin_numeric": "zuo2tian1 shi4 qing2tian1, wo3 xin1qing2 hen3 kai1xin1.",
      "translation_en": "Yesterday was sunny, and I was in a very happy mood.",
      "translation_ko": "어제는 맑은 날씨였고, 저는 기분이 매우 즐거웠습니다."
    },
    {
      "text": "今天溫度三十度，天氣有點熱，我有點想喝冰水。",
      "pinyin": "Jīntiān wēndù sānshí dù, tiānqì yǒudiǎn rè, wǒ yǒudiǎn xiǎng hē bīng shuǐ.",
      "pinyin_numeric": "jin1tian1 wen1du4 san1shi2 du4, tian1qi4 you3dian3 re4, wo3 you3dian3 xiang3 he1 bing1 shui3.",
      "translation_en": "Today's temperature is 30 degrees; the weather is a bit hot, and I feel like drinking some ice water.",
      "translation_ko": "오늘 기온이 30도이고, 날씨가 조금 더워서, 저는 얼음물을 조금 마시고 싶습니다."
    },
    {
      "text": "下雨了，路有點滑，你要小心。",
      "pinyin": "Xià yǔ le, lù yǒudiǎn huá, nǐ yào xiǎoxīn.",
      "pinyin_numeric": "xia4 yu3 le0, lu4 you3dian3 hua2, ni3 yao4 xiao3xin1.",
      "translation_en": "It's raining; the road is a bit slippery, so you need to be careful.",
      "translation_ko": "비가 와서 길이 조금 미끄러우니, 조심하셔야 합니다."
    },
    {
      "text": "今天陰天，我心情有點不好。",
      "pinyin": "Jīntiān yīntiān, wǒ xīnqíng yǒudiǎn bù hǎo.",
      "pinyin_numeric": "jin1tian1 yin1tian1, wo3 xin1qing2 you3dian3 bu4 hao3.",
      "translation_en": "Today is overcast, and I'm in a bit of a bad mood.",
      "translation_ko": "오늘은 흐린 날씨라서, 제 기분이 조금 안 좋습니다."
    },
    {
      "text": "颱風天風很大，我有點緊張。",
      "pinyin": "Táifēng tiān fēng hěn dà, wǒ yǒudiǎn jǐnzhāng.",
      "pinyin_numeric": "tai2feng1 tian1 feng1 hen3 da4, wo3 you3dian3 jin3zhang1.",
      "translation_en": "On a typhoon day, the wind is very strong, and I'm a bit nervous.",
      "translation_ko": "태풍이 오는 날 바람이 매우 세서, 저는 조금 긴장됩니다."
    },
    {
      "text": "今天天氣很舒服，我心情很放鬆。",
      "pinyin": "Jīntiān tiānqì hěn shūfu, wǒ xīnqíng hěn fàngsōng.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 shu1fu0, wo3 xin1qing2 hen3 fang4song1.",
      "translation_en": "The weather is very comfortable today, and I feel very relaxed.",
      "translation_ko": "오늘 날씨가 매우 쾌적해서, 저는 기분이 매우 편안합니다."
    },
    {
      "text": "明天多雲，溫度二十度，天氣有點涼快。",
      "pinyin": "Míngtiān duōyún, wēndù èrshí dù, tiānqì yǒudiǎn liángkuài.",
      "pinyin_numeric": "ming2tian1 duo1yun2, wen1du4 er4shi2 du4, tian1qi4 you3dian3 liang2kuai4.",
      "translation_en": "Tomorrow will be cloudy, with a temperature of 20 degrees; the weather will be a bit cool.",
      "translation_ko": "내일은 구름이 많고 기온이 20도이며, 날씨가 조금 서늘합니다."
    }
  ]
}
